// Watermark: only comments added since the last successful digest
const store = $getWorkflowStaticData('global');
const since = store.lastDigest || new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString();
return [{ json: { since } }];

const body = $input.all()[0]?.json || {};
const results = body.results || [];
const txt = (p, prop) => { const v = p[prop] || {}; const a = v.title || v.rich_text || []; return a[0]?.plain_text || ''; };
const rows = [];
for (const r of results) {
  const p = r.properties || {};
  rows.push({
    text: txt(p, 'Comment'),
    category: (p.Category?.select || {}).name || '',
    reason: txt(p, 'Reason'),
    likes: p.Likes?.number ?? 0,
    url: p.URL?.url || ''
  });
}
const block = rows.map((r, i) => `${i + 1}. [${r.category}] лайков:${r.likes}\n"${r.text}"\nПричина: ${r.reason}\nСсылка: ${r.url}`).join('\n\n');
return [{ json: { count: rows.length, block } }];

// Advance the watermark only after a successful send
const store = $getWorkflowStaticData('global');
store.lastDigest = new Date().toISOString();
return $input.all();
